// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System;
using System.Threading.Tasks;
using Azure.Core;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.CustomerInsights;
using Azure.ResourceManager.CustomerInsights.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.CustomerInsights.Tests.Samples
{
    public class Sample1_HelloWorld : SamplesBase
    {
        [Test]
        [SyncOnly]
        [Ignore(&#34;Only validating compilation of examples&#34;)]
        public async Task CreateHub()
        {
            #region Snippet:CustomerInsightsCreateHub
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = &#34;&#34;;
            string resourceGroupName = &#34;&#34;;
            ResourceIdentifier resourceGroupId = ResourceGroupResource.CreateResourceIdentifier(subscriptionId, resourceGroupName);
            ResourceGroupResource resourceGroup = client.GetResourceGroupResource(resourceGroupId);

            HubCollection hubs = resourceGroup.GetHubs();

            HubData hubData = new HubData(new AzureLocation(&#34;West US&#34;))
            {
                HubBillingInfo = new HubBillingInfoFormat
                {
                    SkuName = &#34;B0&#34;,
                    MinUnits = 1,
                    MaxUnits = 5,
                },
            };

            ArmOperation lro = await hubs.CreateOrUpdateAsync(WaitUntil.Completed, &#34;myHub&#34;, hubData);
            HubResource hub = lro.Value;
            Console.WriteLine($&#34;Created Hub: {hub.Data.Id}&#34;);
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore(&#34;Only validating compilation of examples&#34;)]
        public async Task ListHubs()
        {
            #region Snippet:CustomerInsightsListHubs
            TokenCredential cred = new DefaultAzureCredential();
            ArmClient client = new ArmClient(cred);

            string subscriptionId = &#34;&#34;;
            string resourceGroupName = &#34;&#34;;
            ResourceIdentifier resourceGroupId = ResourceGroupResource.CreateResourceIdentifier(subscriptionId, resourceGroupName);
            ResourceGroupResource resourceGroup = client.GetResourceGroupResource(resourceGroupId);

            await foreach (HubResource hub in resourceGroup.GetHubs())
            {
                Console.WriteLine($&#34;Hub: {hub.Data.Name} in {hub.Data.Location}&#34;);
            }
            #endregion
        }
    }
}
```

### Step 2: Add or update code snippets

1. **Create** the test file at `sdk/customer-insights/Azure.ResourceManager.CustomerInsights/tests/Samples/Sample1_HelloWorld.cs` with the content shown in Step 1.
2. The `#region Snippet:CustomerInsightsCreateHub` and `#region Snippet:CustomerInsightsListHubs` tags in that file correspond to placeholders in the README.
3. After the test file is created, run `eng/scripts/Update-Snippets.ps1 customer-insights` to inject the code into the README.

### Step 3: Verify README structure

Current README issues:
- ✅ `## Getting started` — present with Install, Prerequisites, Authenticate subsections
- ⚠️ `## Key concepts` — present but only a generic link; replace with service-specific content (see Step 1)
- ❌ `## Documentation` — non-standard section; **remove** it
- ⚠️ `## Examples` — present but no actual code; replace with snippet placeholders (see Step 1)
- ✅ `## Troubleshooting` — present
- ✅ `## Next steps` — present
- ✅ `## Contributing` — present

### Step 4: Validate

Run these commands in order:

1. `dotnet build sdk/customer-insights/Azure.ResourceManager.CustomerInsights/`
2. `dotnet test sdk/customer-insights/Azure.ResourceManager.CustomerInsights/ --filter TestCategory!=Live`
3. `eng/scripts/Update-Snippets.ps1 customer-insights` — injects snippet code into the README placeholders; verify with `git diff` that README was updated
4. `eng/scripts/Export-API.ps1 customer-insights` — no public API changes expected, but run to confirm API listing files are current
5. `dotnet format sdk/customer-insights/Azure.ResourceManager.CustomerInsights/`



